request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?name ?type WHERE {
  ?pkg rdf:type vocab:package .
  OPTIONAL { ?pkg vocab:NamedElement_name ?name }
  OPTIONAL { ?pkg rdf:type ?type }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?comment ?body ?annotatedElement WHERE {
  ?comment rdf:type vocab:comment .
  ?comment vocab:Comment_body ?body .
  OPTIONAL { ?comment vocab:Comment_annotatedElement ?annotatedElement }
}
LIMIT 25
